#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using MVZ2Logic.Options;
using PVZEngine;
using TMPro;
using UnityEngine;
using UnityEngine.UI;
using static UnityEditor.Progress;

namespace MVZ2.UI
{
    public class OptionWidgets : MonoBehaviour, IOptionsDialogElement
    {
        public NamespaceID? GetOptionID()
        {
            return optionID;
        }
        public void SetSliderText(string text)
        {
            slider.Text.text = text;
        }
        public void SetButtonText(string text)
        {
            button.Text.text = text;
        }
        public void SetDropdownValue(int value)
        {
            dropdown.Dropdown.SetValueWithoutNotify(value);
        }
        public void SetDropdownOptions(List<string> options)
        {
            dropdown.Dropdown.ClearOptions();
            dropdown.Dropdown.AddOptions(options);
        }
        public void UpdateWidgets(OptionWidgetsViewData viewData)
        {
            optionID = viewData.namespaceID;
            switch (viewData.type)
            {
                case OptionWidgetType.Toggle:
                    UpdateToggle(viewData);
                    break;
                case OptionWidgetType.Slider:
                    UpdateSlider(viewData);
                    break;
                case OptionWidgetType.Dropdown:
                    UpdateDropdown(viewData);
                    break;
                case OptionWidgetType.Button:
                    UpdateButton(viewData);
                    break;
            }
        }
        private void UpdateToggle(OptionWidgetsViewData viewData)
        {
            toggle.gameObject.SetActive(true);
            slider.gameObject.SetActive(false);
            dropdown.gameObject.SetActive(false);
            button.gameObject.SetActive(false);

            toggle.Text.text = viewData.label;

            if (viewData.value is bool boolValue)
            {
                toggle.Toggle.SetIsOnWithoutNotify(boolValue);
            }
        }
        private void UpdateSlider(OptionWidgetsViewData viewData)
        {
            toggle.gameObject.SetActive(false);
            slider.gameObject.SetActive(true);
            dropdown.gameObject.SetActive(false);
            button.gameObject.SetActive(false);

            slider.Text.text = viewData.label;

            slider.Slider.wholeNumbers = viewData.sliderWholeNumbers;
            slider.Slider.minValue = viewData.sliderMinValue;
            slider.Slider.maxValue = viewData.sliderMaxValue;

            if (viewData.value is float floatValue)
            {
                slider.Slider.SetValueWithoutNotify(floatValue);
            }
        }
        private void UpdateDropdown(OptionWidgetsViewData viewData)
        {
            toggle.gameObject.SetActive(false);
            slider.gameObject.SetActive(false);
            dropdown.gameObject.SetActive(true);
            button.gameObject.SetActive(false);

            dropdown.Text.text = viewData.label;
            dropdown.Dropdown.ClearOptions();
            dropdown.Dropdown.AddOptions(viewData.dropdownOptions);

            if (viewData.value is int index)
            {
                dropdown.Dropdown.SetValueWithoutNotify(index);
            }
        }
        private void UpdateButton(OptionWidgetsViewData viewData)
        {
            toggle.gameObject.SetActive(false);
            slider.gameObject.SetActive(false);
            dropdown.gameObject.SetActive(false);
            button.gameObject.SetActive(true);

            button.Text.text = viewData.label;
        }
        private void Awake()
        {
            toggle.Toggle.onValueChanged.AddListener(v => OnToggleValueChanged?.Invoke(this, v));
            slider.Slider.onValueChanged.AddListener(v => OnSliderValueChanged?.Invoke(this, v));
            if (slider.EndHandler.Exists())
                slider.EndHandler.OnEnd += data => OnSliderEnd?.Invoke(this, slider.Slider.value);
            dropdown.Dropdown.onValueChanged.AddListener(v => OnDropdownValueChanged?.Invoke(this, v));
            button.Button.onClick.AddListener(() => OnButtonClicked?.Invoke(this));
        }
        public event Action<OptionWidgets, bool>? OnToggleValueChanged;
        public event Action<OptionWidgets, float>? OnSliderValueChanged;
        public event Action<OptionWidgets, float>? OnSliderEnd;
        public event Action<OptionWidgets, int>? OnDropdownValueChanged;
        public event Action<OptionWidgets>? OnButtonClicked;
        public LabeledToggle Toggle => toggle;
        public TextSlider Slider => slider;
        public LabeledDropdown Dropdown => dropdown;
        public TextButton TextButton => button;
        private NamespaceID? optionID;

        [SerializeField]
        private LabeledToggle toggle = null!;
        [SerializeField]
        private TextSlider slider = null!;
        [SerializeField]
        private LabeledDropdown dropdown = null!;
        [SerializeField]
        private TextButton button = null!;
    }
    public struct OptionWidgetsViewData
    {
        public OptionWidgetType type;
        public string label;
        public object? value;
        public bool sliderWholeNumbers;
        public float sliderMinValue;
        public float sliderMaxValue;
        public string tooltipText;
        public string tooltipContext;
        public NamespaceID namespaceID;
        public List<string> dropdownOptions;
    }
}
